import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Plus, BarChart2, Search, Trophy, Filter, RotateCcw, Clock } from 'lucide-react';
import toast from 'react-hot-toast';
import { projectsApi, tasksApi, usersApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { StatusBadge, PriorityBadge } from '../components/common/Badge';
import Modal from '../components/common/Modal';
import Avatar from '../components/common/Avatar';
import { getStatusLabel, getPriorityClass, formatDate, getErrorMessage, isOverdue, isDueSoon } from '../utils/helpers';
import { joinProject, leaveProject, getSocket } from '../services/socket';

const COLUMNS = ['TODO','IN_PROGRESS','REVIEW','DONE'];
const COL_COLORS = { TODO:'var(--text-3)', IN_PROGRESS:'var(--primary)', REVIEW:'var(--purple)', DONE:'var(--green)' };
const COL_BG = { TODO:'var(--bg-subtle)', IN_PROGRESS:'var(--primary-bg)', REVIEW:'var(--purple-bg)', DONE:'var(--green-bg)' };

function TaskCard({ task, project, onClick }) {
  const overdue = isOverdue(task.dueDate) && task.status !== 'DONE';
  const dueSoon = isDueSoon(task.dueDate) && task.status !== 'DONE';

  return (
    <div className="kanban-card" onClick={()=>onClick(task)}>
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
        <span className="kanban-card-id">{project?.key}-{task.taskNumber}</span>
        <PriorityBadge priority={task.priority}/>
      </div>
      <p className="kanban-card-title">{task.title}</p>
      {task.dependencies?.length > 0 && (
        <div style={{marginBottom:6}}>
          {task.dependencies.some(d=>d.status!=='DONE') && (
            <span className="dep-badge dep-blocked">⛔ {task.dependencies.filter(d=>d.status!=='DONE').length} blocked</span>
          )}
        </div>
      )}
      <div className="kanban-card-footer">
        {task.dueDate ? (
          <span style={{fontSize:'.72rem',fontWeight:500,color:overdue?'var(--red-text)':dueSoon?'var(--yellow-text)':'var(--text-3)'}}>
            {overdue?'⚠ ':dueSoon?'⏰ ':''}{formatDate(task.dueDate)}
          </span>
        ) : <span/>}
        <div style={{display:'flex',alignItems:'center',gap:-4}}>
          {task.assignee && <Avatar name={task.assignee.name} size="sm"/>}
        </div>
      </div>
    </div>
  );
}

function CreateTaskModal({ open, onClose, onCreated, projectId, members }) {
  const { user } = useAuth();
  const [form, setForm] = useState({ title:'',description:'',priority:'MEDIUM',status:'TODO',dueDate:'',assignee:'' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title) return toast.error('Title is required');
    setLoading(true);
    try {
      const {data} = await tasksApi.create(projectId, {...form, assignee:form.assignee||undefined});
      onCreated(data.task); toast.success('Task created');
    } catch(err) { toast.error(getErrorMessage(err)); }
    finally { setLoading(false); }
  };

  return (
    <Modal open={open} onClose={onClose} title="Create Task">
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label className="form-label">Title *</label>
          <input className="input" placeholder="Task title" value={form.title} autoFocus
            onChange={e=>setForm(f=>({...f,title:e.target.value}))}/>
        </div>
        <div className="form-group">
          <label className="form-label">Description</label>
          <textarea className="input" rows={2} placeholder="Describe the task…"
            value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))}/>
        </div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'1rem'}}>
          <div className="form-group">
            <label className="form-label">Status</label>
            <select className="input" value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}>
              {COLUMNS.map(s=><option key={s} value={s}>{getStatusLabel(s)}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Priority</label>
            <select className="input" value={form.priority} onChange={e=>setForm(f=>({...f,priority:e.target.value}))}>
              {['LOW','MEDIUM','HIGH'].map(p=><option key={p} value={p}>{p}</option>)}
            </select>
          </div>
        </div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'1rem'}}>
          <div className="form-group">
            <label className="form-label">Assignee</label>
            <select className="input" value={form.assignee} onChange={e=>setForm(f=>({...f,assignee:e.target.value}))}>
              <option value="">Unassigned</option>
              {(members||[]).map(m=><option key={m.user._id} value={m.user._id}>{m.user.name}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Due Date</label>
            <input className="input" type="date" value={form.dueDate} onChange={e=>setForm(f=>({...f,dueDate:e.target.value}))}/>
          </div>
        </div>
        <div style={{display:'flex',gap:'.75rem',justifyContent:'flex-end',marginTop:'.25rem'}}>
          <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button type="submit" className="btn btn-primary" disabled={loading}>
            {loading?<span className="spinner"/>:<><Plus size={14}/> Create Task</>}
          </button>
        </div>
      </form>
    </Modal>
  );
}

