      <select className="input" style={{width:'auto',fontSize:'.8rem',padding:'.3rem .65rem'}}
        value={filters.priority} onChange={e=>setFilters(f=>({...f,priority:e.target.value}))}>
        <option value="">All priorities</option>
        {['LOW','MEDIUM','HIGH'].map(p=><option key={p} value={p}>{p}</option>)}
      </select>
      <select className="input" style={{width:'auto',fontSize:'.8rem',padding:'.3rem .65rem'}}
        value={filters.assignee} onChange={e=>setFilters(f=>({...f,assignee:e.target.value}))}>
        <option value="">All assignees</option>
