    </div>
  );
}

export default function ProjectDetailPage() {
  const { projectId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [project, setProject] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [activeTab, setActiveTab] = useState('board');
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState({ status:'', priority:'', assignee:'', search:'' });

  const loadData = useCallback(async () => {
    try {
      const [pRes, tRes] = await Promise.all([
        projectsApi.get(projectId),
        tasksApi.list(projectId, { limit:200, isDeleted:false }),
      ]);
      setProject(pRes.data.project);
      setTasks(tRes.data.tasks||[]);
    } catch { toast.error('Failed to load project'); }
    finally { setLoading(false); }
  }, [projectId]);

  useEffect(() => {
    loadData();
    joinProject(projectId);
    const socket = getSocket();
    if (socket) {
      socket.on('task_created', t=>setTasks(prev=>[t,...prev]));
      socket.on('task_updated', t=>setTasks(prev=>prev.map(x=>x._id===t._id?t:x)));
      socket.on('task_status_changed', ({taskId,status})=>setTasks(prev=>prev.map(x=>x._id===taskId?{...x,status}:x)));
      socket.on('task_deleted', ({taskId})=>setTasks(prev=>prev.filter(x=>x._id!==taskId)));
    }
    return () => {
      leaveProject(projectId);
      if (socket) { socket.off('task_created'); socket.off('task_updated'); socket.off('task_status_changed'); socket.off('task_deleted'); }
    };
  }, [projectId, loadData]);

  // Filter logic
  const filtered = tasks.filter(t => {
    if (filters.status && t.status !== filters.status) return false;
    if (filters.priority && t.priority !== filters.priority) return false;
    if (filters.assignee === 'unassigned' && t.assignee) return false;
    if (filters.assignee && filters.assignee !== 'unassigned' && t.assignee?._id !== filters.assignee) return false;
    if (filters.search && !t.title.toLowerCase().includes(filters.search.toLowerCase())) return false;
    return true;
  });

  const byStatus = COLUMNS.reduce((acc,s) => { acc[s]=filtered.filter(t=>t.status===s); return acc; }, {});

  if (loading) return <div className="spinner-center"><div className="spinner spinner-lg"/></div>;
  if (!project) return <div className="empty-state"><p>Project not found</p></div>;

  return (
    <div>
      {/* Breadcrumb + header */}
      <div style={{marginBottom:'1.25rem'}}>
        <div style={{display:'flex',alignItems:'center',gap:6,marginBottom:8,fontSize:'.82rem',color:'var(--text-3)'}}>
          <button className="btn btn-ghost btn-sm" style={{padding:'2px 6px'}} onClick={()=>navigate('/projects')}>Projects</button>
          <span>/</span>
          <span style={{color:'var(--text-2)',fontWeight:500}}>{project.name}</span>
        </div>
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',flexWrap:'wrap',gap:'1rem'}}>
          <div style={{display:'flex',alignItems:'center',gap:10}}>
            <span style={{fontFamily:'ui-monospace,monospace',fontSize:'.75rem',fontWeight:700,background:'var(--primary-bg)',color:'var(--primary-text)',padding:'3px 9px',borderRadius:6}}>
              {project.key}
            </span>
            <h1 style={{fontSize:'1.25rem',fontWeight:800,letterSpacing:'-.02em'}}>{project.name}</h1>
          </div>
          <div style={{display:'flex',gap:'.5rem'}}>
            <button className="btn btn-secondary btn-sm" onClick={()=>navigate(`/leaderboard/${projectId}`)}>
              <Trophy size={14}/> Leaderboard
            </button>
            <button className="btn btn-secondary btn-sm" onClick={()=>navigate(`/analytics/${projectId}`)}>
              <BarChart2 size={14}/> Analytics
            </button>
            <button className="btn btn-primary btn-sm" onClick={()=>setShowCreate(true)}>
              <Plus size={14}/> Add Task
            </button>
          </div>
        </div>
        {project.description && <p className="text-2 text-sm" style={{marginTop:6}}>{project.description}</p>}
      </div>

      {/* Tabs + search */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'1rem',flexWrap:'wrap',gap:'.75rem'}}>
        <div style={{display:'flex',alignItems:'center',gap:'.5rem'}}>
          <div className="tabs">
            {['board','list','members'].map(tab=>(
              <button key={tab} className={`tab-btn${activeTab===tab?' active':''}`} onClick={()=>setActiveTab(tab)}>
                {tab.charAt(0).toUpperCase()+tab.slice(1)}
              </button>
            ))}
          </div>
          <button className={`btn btn-sm ${showFilters?'btn-primary':'btn-secondary'}`} onClick={()=>setShowFilters(f=>!f)}>
            <Filter size={13}/> Filters
          </button>
        </div>
        <div className="header-search" style={{minWidth:0}}>
          <Search size={13}/>
          <input placeholder="Search tasks…" value={filters.search}
            onChange={e=>setFilters(f=>({...f,search:e.target.value}))}/>
        </div>
      </div>

      {showFilters && (
        <div style={{marginBottom:'1rem',padding:'.75rem 1rem',background:'var(--bg-subtle)',border:'1px solid var(--border)',borderRadius:'var(--radius)',display:'flex',flexWrap:'wrap',gap:'.5rem',alignItems:'center'}}>
          <Filter size={13} style={{color:'var(--text-3)'}}/>
          <FilterBar filters={filters} setFilters={setFilters} members={project.members}/>
        </div>
      )}

      {/* Board */}
      {activeTab==='board' && (
        <div className="kanban-board">
          {COLUMNS.map(col=>(
            <div key={col} className="kanban-col">
              <div className="kanban-col-header">
                <div style={{display:'flex',alignItems:'center',gap:7}}>
                  <span style={{width:8,height:8,borderRadius:'50%',background:COL_COLORS[col],flexShrink:0}}/>
                  <span className="kanban-col-title" style={{color:COL_COLORS[col]}}>{getStatusLabel(col)}</span>
                </div>
                <span className="kanban-col-count">{byStatus[col].length}</span>
              </div>
              <div className="kanban-cards">
                {byStatus[col].map(task=>(
                  <TaskCard key={task._id} task={task} project={project}
                    onClick={()=>navigate(`/projects/${projectId}/tasks/${task._id}`)}/>
                ))}
                {byStatus[col].length===0 && (
                  <div style={{textAlign:'center',padding:'1.5rem 0',color:'var(--text-3)',fontSize:'.8rem'}}>
                    No tasks
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* List */}
      {activeTab==='list' && (
        <div className="card" style={{padding:0,overflow:'hidden'}}>
          <div className="table-wrap">
            <table className="table">
              <thead><tr><th>ID</th><th>Title</th><th>Status</th><th>Priority</th><th>Assignee</th><th>Due</th></tr></thead>
              <tbody>
                {filtered.map(task=>(
                  <tr key={task._id} style={{cursor:'pointer'}} onClick={()=>navigate(`/projects/${projectId}/tasks/${task._id}`)}>
                    <td><span className="mono text-xs text-3">{project.key}-{task.taskNumber}</span></td>
                    <td style={{color:'var(--text)',fontWeight:500,maxWidth:320}}>
                      {task.title}
                      {task.dependencies?.some(d=>d.status!=='DONE') && (
                        <span className="dep-badge dep-blocked" style={{marginLeft:8}}>blocked</span>
                      )}
                    </td>
                    <td><StatusBadge status={task.status}/></td>
                    <td><PriorityBadge priority={task.priority}/></td>
                    <td>
                      {task.assignee
                        ? <div style={{display:'flex',alignItems:'center',gap:6}}><Avatar name={task.assignee.name} size="sm"/><span className="text-sm">{task.assignee.name}</span></div>
                        : <span className="text-3 text-sm">—</span>}
                    </td>
                    <td>
                      <span style={{fontSize:'.82rem',color:isOverdue(task.dueDate)&&task.status!=='DONE'?'var(--red-text)':isDueSoon(task.dueDate)?'var(--yellow-text)':'var(--text-2)'}}>
                        {formatDate(task.dueDate)}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filtered.length===0 && <div className="empty-state"><p>No tasks match your filters</p></div>}
          </div>
        </div>
      )}

      {/* Members */}
      {activeTab==='members' && (
        <div className="card" style={{padding:0,overflow:'hidden'}}>
          <table className="table">
            <thead><tr><th>Member</th><th>Email</th><th>Role</th><th>Joined</th></tr></thead>
            <tbody>
              {(project.members||[]).map(m=>(
                <tr key={m._id}>
                  <td>
                    <div style={{display:'flex',alignItems:'center',gap:9}}>
                      <Avatar name={m.user?.name} size="sm"/>
                      <span style={{fontWeight:600,color:'var(--text)',fontSize:'.875rem'}}>{m.user?.name}</span>
                    </div>
                  </td>
                  <td className="text-sm">{m.user?.email}</td>
                  <td><span className={`badge ${m.role==='ADMIN'?'badge-progress':'badge-todo'}`}>{m.role}</span></td>
                  <td className="text-sm text-3">{formatDate(m.joinedAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <CreateTaskModal open={showCreate} onClose={()=>setShowCreate(false)} projectId={projectId}
        members={project.members}
        onCreated={t=>{ setTasks(prev=>[t,...prev]); setShowCreate(false); }}/>
    </div>
  );
}
